static common_chat_params common_chat_templates_apply_jinja(
    const struct common_chat_templates * tmpls,
    const struct common_chat_templates_inputs & inputs) {
    // ... prepare generation params ...

    // Select appropriate template (tool_use if tools present, else default)
    const auto & tmpl =
        params.tools.is_array() && tmpls->template_tool_use ? 
            *tmpls->template_tool_use : *tmpls->template_default;

    // ... render template ...

    // Try specialized template first (fallback handler)
    if (auto result = common_chat_try_specialized_template(tmpl, src, params)) {
        return *result;
    }

    // Fall back to differential autoparser (generates PEG parser automatically)
    struct autoparser::autoparser autoparser;
    autoparser.analyze_template(tmpl);
    auto auto_params = autoparser::peg_generator::generate_parser(tmpl, params, autoparser);
    return auto_params;
}

common_chat_params common_chat_templates_apply(
    const struct common_chat_templates * tmpls,
    const struct common_chat_templates_inputs & inputs) {
    GGML_ASSERT(tmpls != nullptr);
    return inputs.use_jinja ? common_chat_templates_apply_jinja(tmpls, inputs) :
                              common_chat_templates_apply_legacy(tmpls, inputs);
